import { Box, LinearProgress, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { useTT } from "../../useTT.ts";
import { useIsColumnSelected } from "../SelectionContext.tsx";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { formatCashflowAmount } from "../utils/index.ts";
import type { CashflowTableCellProps } from "./types/index.ts";

/**
 * Reusable table cell component for the cashflow table.
 *
 * Performance: Memoized to prevent unnecessary re-renders. With 140+ cells
 * (7 periods x 20 categories), React.memo combined with useIsColumnSelected
 * ensures only cells whose highlight status changes re-render (typically ~14
 * cells during column highlighting: 7 cells losing highlight + 7 gaining it).
 */
function CashflowTableCellComponent({
  value,
  columnIndex,
  dateFrom,
  isBold = false,
  progressPercentage,
  colorMode,
  onClick,
}: CashflowTableCellProps) {
  const { language } = useTT();
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box>
        {formatCashflowAmount(value, language)}
        {progressPercentage !== undefined && (
          <LinearProgress
            variant="determinate"
            value={progressPercentage}
            sx={{
              mt: 0.5,
              height: 4,
              borderRadius: 1,
              backgroundColor: "action.hover",
              "& .MuiLinearProgress-bar": {
                backgroundColor:
                  progressPercentage > 100 ? "warning.main" : "primary.main",
              },
            }}
          />
        )}
      </Box>
    </TableCell>
  );
}

// Determine text color based on value
function getValueColor(
  colorMode: CashflowTableCellProps["colorMode"],
  value: number,
) {
  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableCell = memo(CashflowTableCellComponent);
CashflowTableCell.displayName = "CashflowTableCell";

import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: "balance" | "final" | "none";
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
              variant="icon"
            />
            <CurrencyAmount
              notation="compact"
              value={value}
              currency={currency}
              naturalPrecision
            />
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

function getValueColor(
  colorMode: CashflowTableSummaryValueCellProps["colorMode"],
  value: number | null,
) {
  if (value === null) {
    return "text.primary";
  }

  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import {
  Box,
  IconButton,
  SxProps,
  TableCell,
  TableRow,
  Theme,
  Tooltip,
} from "@mui/material";
import { type ReactNode, useCallback, useState } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { IconChevronDown } from "@dfp/react-icons";
import { createCheckedContext } from "@dfp/react-utils";

import { useTT } from "../../../useTT.ts";
import { useSelectedColumn } from "../../SelectionContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { CategoryType } from "../types/index.ts";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const [CashflowCategoryProvider, useCashflowCategory] =
  createCheckedContext<CashflowCategoryContextValue>("CashflowCategoryContext");

type CashflowCategoryProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowCategory({
  children,
  defaultExpanded = true,
}: CashflowCategoryProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);

  const toggleExpanded = () => setIsExpanded((prev) => !prev);

  return (
    <CashflowCategoryProvider value={{ isExpanded, toggleExpanded }}>
      {children}
    </CashflowCategoryProvider>
  );
}

type CashflowCategoryHeaderProps = {
  children: ReactNode;
};

export function CashflowCategoryHeader({
  children,
}: CashflowCategoryHeaderProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryHeaderTitleProps = {
  children: ReactNode;
};

export function CashflowCategoryHeaderTitle({
  children,
}: CashflowCategoryHeaderTitleProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
        {children}
      </Box>
    </TableCell>
  );
}

type CashflowCategoryHeaderIconProps = {
  children: ReactNode;
  sx: SxProps<Theme>;
};

export function CashflowCategoryHeaderIcon({
  children,
  sx,
}: CashflowCategoryHeaderIconProps) {
  return (
    <Box
      component="span"
      sx={{
        fontSize: "1.2em",
        ...sx,
      }}
    >
      {children}
    </Box>
  );
}

type CashflowCategoryRowProps = {
  children: ReactNode;
};

export function CashflowCategoryRow({ children }: CashflowCategoryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryRowLabelProps = {
  children: ReactNode;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryRowLabel({
  children,
  category,
  direction,
}: CashflowCategoryRowLabelProps) {
  const selectedColumn = useSelectedColumn();

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel: children,
  });

  const handleClick = useCallback(() => {
    if (selectedColumn == null) return;
    openDetail(selectedColumn);
  }, [selectedColumn, openDetail]);

  return (
    <TableCell
      onClick={handleClick}
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        paddingLeft: 4,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: "pointer",
      }}
    >
      <Tooltip title={children} placement="top-start">
        <Box
          component="span"
          sx={{
            display: "block",
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
            "&:hover": {
              textDecoration: "underline",
            },
          }}
        >
          {children}
        </Box>
      </Tooltip>
    </TableCell>
  );
}

type CashflowCategoryTriggerProps = {
  categoryType: "income" | "costs";
};

export function CashflowCategoryTrigger({
  categoryType,
}: CashflowCategoryTriggerProps) {
  const { isExpanded, toggleExpanded } = useCashflowCategory();
  const { tt } = useTT();

  const ariaLabel = isExpanded
    ? tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.collapseIncome"
          : "cashflowTable.accessibility.collapseCosts",
      )
    : tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.expandIncome"
          : "cashflowTable.accessibility.expandCosts",
      );

  return (
    <IconButton
      size="small"
      onClick={toggleExpanded}
      aria-expanded={isExpanded}
      aria-label={ariaLabel}
      sx={{
        ml: "auto",
        transform: isExpanded ? "rotate(180deg)" : "rotate(0deg)",
        transition: "transform 0.2s",
      }}
    >
      <IconChevronDown />
    </IconButton>
  );
}

type CashflowCategoryRowsProps = {
  children: ReactNode;
};

export function CashflowCategoryRows({ children }: CashflowCategoryRowsProps) {
  const { isExpanded } = useCashflowCategory();

  return isExpanded ? <>{children}</> : null;
}

import { TableCell, TableRow } from "@mui/material";
import { ReactNode } from "react";

import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";

type CashflowTableSummaryRowProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRow({
  children,
}: CashflowTableSummaryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowTableSummaryRowLabelProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRowLabel({
  children,
}: CashflowTableSummaryRowLabelProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      {children}
    </TableCell>
  );
}

import { IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Income category breakdown with collapsible section.
 *
 * Structure:
 * - Income section header (with total, expandable)
 *   - Income category rows (indented)
 */
export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "success.main" }}>
            <IconArrowUpRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.income")}
          <CashflowCategoryTrigger categoryType="income" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.income}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.income.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="IN"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import { IconArrowDownRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Costs category breakdown with collapsible section.
 *
 * Structure:
 * - Costs section header (with total, expandable)
 *   - Cost category rows (indented)
 */
export function CashflowTableCostsCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "error.main" }}>
            <IconArrowDownRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.costs")}
          <CashflowCategoryTrigger categoryType="costs" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.costs}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.costs.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="OUT"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import {
  Paper,
  Table,
  TableBody,
  TableContainer,
  TableHead,
} from "@mui/material";

import { useTT } from "../../useTT.ts";
import { CashflowTableCostsCategories } from "./CashflowTableCostsCategories.tsx";
import { CashflowTableFinalBalanceRow } from "./CashflowTableFinalBalanceRow.tsx";
import { CashflowTableHeader } from "./CashflowTableHeader.tsx";
import { CashflowTableIncomeCategories } from "./CashflowTableIncomeCategories.tsx";
import { CashflowTableNetBalanceRow } from "./CashflowTableNetBalanceRow.tsx";

/**
 * Main cashflow table component.
 *
 * Layout (top to bottom):
 * 1. Header
 * 2. Income section header (expandable) + income categories
 * 3. Costs section header (expandable) + cost categories
 * 4. Net Balance
 * 5. Final Balance
 *
 * Features:
 * - Collapsible Income and Costs sections with totals
 * - Dynamically renders all periods returned by the API
 * - Full content height (page scrolls instead of table)
 */
export function CashflowTable() {
  const { tt } = useTT();

  return (
    <TableContainer component={Paper}>
      <Table
        sx={{ tableLayout: "fixed", borderCollapse: "separate" }}
        aria-label={tt("cashflowTable.accessibility.tableLabel")}
      >
        <TableHead>
          <CashflowTableHeader />
        </TableHead>

        <TableBody>
          <CashflowTableIncomeCategories />
        </TableBody>
        <TableBody>
          <CashflowTableCostsCategories />
        </TableBody>

        <TableBody>
          <CashflowTableNetBalanceRow />
          <CashflowTableFinalBalanceRow />
        </TableBody>
      </Table>
    </TableContainer>
  );
}

import { DateView } from "@mui/x-date-pickers";
import { Dayjs } from "dayjs";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type MonthPickerProps = {
  onMonthChange: (date: Dayjs) => void;
};

export function MonthPicker({ onMonthChange }: MonthPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<DateView>("month");

  return (
    <StaticCalendar
      value={value}
      view={view}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "260px",
        },
      }}
      onViewChange={setView}
      onChange={(val) => {
        setValue(val);
        if (view === "month" && val) {
          onMonthChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month"]}
      openTo="month"
    />
  );
}

import { PickersDay } from "@mui/x-date-pickers";
import type { PickersDayProps } from "@mui/x-date-pickers/PickersDay";
import { Dayjs } from "dayjs";
import type { ComponentType } from "react";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type WeekPickerProps = {
  onWeekChange: (date: Dayjs) => void;
};

export function WeekPicker({ onWeekChange }: WeekPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<"year" | "month" | "day">("day");

  return (
    <StaticCalendar
      value={value}
      view={view}
      onViewChange={setView}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "354px",
        },
        "& .MuiPickersSlideTransition-root": {
          minHeight: "260px",
        },
      }}
      onChange={(val) => {
        setValue(val);
        if (view === "day" && val) {
          onWeekChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month", "day"]}
      showDaysOutsideCurrentMonth
      slots={{
        day: WeekPickerDay as ComponentType<PickersDayProps<Dayjs>>,
      }}
      slotProps={{
        day: {
          selectedDay: value,
          minDate: maxDateRangeFrom,
          maxDate: maxDateRangeTo,
        } as Record<string, unknown>,
      }}
    />
  );
}

type WeekPickerDayProps = PickersDayProps<Dayjs> & {
  selectedDay: Dayjs | null;
  minDate: Dayjs;
  maxDate: Dayjs;
};

/**
 * Custom day component that highlights the entire week row when in week view
 */
export function WeekPickerDay({
  day,
  selectedDay,
  minDate,
  maxDate,
  ...other
}: WeekPickerDayProps) {
  if (!selectedDay) {
    return <PickersDay {...other} day={day} />;
  }

  const startOfWeek = selectedDay.startOf("isoWeek");
  const endOfWeek = selectedDay.endOf("isoWeek");
  const isInSelectedWeek =
    day.isSame(startOfWeek, "day") ||
    (day.isAfter(startOfWeek) && day.isBefore(endOfWeek)) ||
    day.isSame(endOfWeek, "day");

  const isStartOfWeek = day.isSame(startOfWeek, "day");
  const isEndOfWeek = day.isSame(endOfWeek, "day");

  // Disable days outside the available range
  const isOutsideRange =
    day.isBefore(minDate, "day") || day.isAfter(maxDate, "day");

  return (
    <PickersDay
      {...other}
      day={day}
      disabled={isOutsideRange}
      disableMargin
      selected={isInSelectedWeek}
      sx={{
        padding: 2.5,
        ...(isInSelectedWeek && {
          backgroundColor: "primary.main",
          color: "primary.contrastText",
          borderRadius: 0,
          "&:hover": {
            backgroundColor: "primary.dark",
          },
          "&:focus": {
            backgroundColor: "primary.main",
          },
        }),
        ...(isStartOfWeek &&
          isInSelectedWeek && {
            borderTopLeftRadius: "50%",
            borderBottomLeftRadius: "50%",
          }),
        ...(isEndOfWeek &&
          isInSelectedWeek && {
            borderTopRightRadius: "50%",
            borderBottomRightRadius: "50%",
          }),
      }}
    />
  );
}

