import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo, type ReactNode } from "react";

import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";

export type CashflowTableValueColorMode = "balance" | "final" | "none";

type CashflowTableValueCellProps = {
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: CashflowTableValueColorMode;
  onClick?: () => void;
  children: ReactNode;
  color?: string;
};

function CashflowTableValueCellComponent({
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode = "none",
  onClick,
  children,
  color = getValueColor(colorMode),
}: CashflowTableValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color,
        boxSizing: "border-box",
      }}
    >
      <Box>{children}</Box>
    </TableCell>
  );
}

function getValueColor(mode: CashflowTableValueColorMode) {
  if (mode === "none") {
    return "text.primary";
  }

  return "text.primary";
}

export const CashflowTableValueCell = memo(CashflowTableValueCellComponent);
CashflowTableValueCell.displayName = "CashflowTableValueCell";

export function CashflowLabelCell({
  children,
  bold = false,
  interactive = false,
}: {
  children: ReactNode;
  bold?: boolean;
  interactive?: boolean;
}) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: bold ? 600 : 400,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: interactive ? "pointer" : undefined,
      }}
    >
      {children}
    </TableCell>
  );
}

import { IconArrowDownRight, IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import { CashflowTableValueCell } from "./components/CashflowTableValueCell.tsx";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";

type CashflowTableCategorySectionProps = {
  kind: "income" | "costs";
};

const sectionPresets = {
  income: {
    titleKey: "cashflowTable.rows.income",
    icon: IconArrowUpRight,
    iconColor: "success.main",
    categoryType: "income" as const,
    direction: "IN" as const,
    totalSelector: (period: { income: number }) => period.income,
    filterSelector: (categoryFilter: { income: string[] }) => categoryFilter.income,
  },
  costs: {
    titleKey: "cashflowTable.rows.costs",
    icon: IconArrowDownRight,
    iconColor: "error.main",
    categoryType: "costs" as const,
    direction: "OUT" as const,
    totalSelector: (period: { costs: number }) => period.costs,
    filterSelector: (categoryFilter: { costs: string[] }) => categoryFilter.costs,
  },
};

export function CashflowTableCategorySection({ kind }: CashflowTableCategorySectionProps) {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();
  const preset = sectionPresets[kind];
  const Icon = preset.icon;

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: preset.iconColor }}>
            <Icon />
          </CashflowCategoryHeaderIcon>
          {tt(preset.titleKey)}
          <CashflowCategoryTrigger categoryType={preset.categoryType} />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableValueCell
            key={period.id}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
          >
            {preset.totalSelector(period as any)}
          </CashflowTableValueCell>
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {preset.filterSelector(categoryFilter as any).map((category: string) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction={preset.direction}
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import { type DateView } from "@mui/x-date-pickers";
import { Dayjs } from "dayjs";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";

export function useControlledCalendarPicker(commitView: DateView) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();
  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<DateView>(commitView);

  const handleChange = (
    onCommit: (date: Dayjs) => void,
    val: Dayjs | null,
    currentView: DateView,
  ) => {
    setValue(val);
    if (currentView === commitView && val) {
      onCommit(val);
    }
  };

  return {
    value,
    view,
    setView,
    handleChange,
    minDate: maxDateRangeFrom,
    maxDate: maxDateRangeTo,
  };
}

